const data = items[0].json;

// 🔹 Dados básicos
const resultados = data.resultados || [];
const codigo = data.codigo || "";
const completarCadastroUrl = data.completar_cadastro_url || "";
const numero = data.telefone || data.numero;

// 🔹 Normalizador (ESSENCIAL)
const getItem = (r) => r.item || r;

// 🔹 Separar por escopo
const nacionais = resultados.filter(r => getItem(r).escopo === "nacional");
const locais = resultados.filter(r => getItem(r).escopo === "local");

// 🔹 Ordenar por nota
const ordenarPorNota = (arr) =>
  [...arr].sort((a, b) => (getItem(b).nota ?? 0) - (getItem(a).nota ?? 0));

// 🔹 Selecionar 2 de cada
const topNacionais = ordenarPorNota(nacionais).slice(0, 2);
const topLocais = ordenarPorNota(locais).slice(0, 2);

// 🔹 Formatter
const formatarLista = (lista) => {
  return lista
    .map((r) => {
      const item = getItem(r);
      const nome = item.razao_social || "Fornecedor";
      const modelo = item.modelo_negocio ? ` (${item.modelo_negocio})` : "";
      const site = item.site || "";
      return `- ${nome}${modelo}\n${site}`;
    })
    .join("\n");
};

// 🔹 Blocos
let blocoNacionais = "";
if (topNacionais.length > 0) {
  blocoNacionais = `Nacionais:\n${formatarLista(topNacionais)}`;
}

let blocoLocais = "";
if (topLocais.length > 0) {
  blocoLocais = `Locais:\n${formatarLista(topLocais)}`;
}

// 🔹 Mensagem
let mensagem = `Da uma olhada nesses fornecedores aqui:`;

// 🔹 Inserção dos blocos
if (blocoNacionais) {
  mensagem += `\n\n${blocoNacionais}`;
}

if (blocoLocais) {
  mensagem += `\n\n${blocoLocais}`;
}

// 🔹 CTA (sempre com código)
mensagem += `\n\nTem mais alguns fornecedores na nossa plataforma, para acessar só clicar no link abaixo, utilizando o código: ${codigo}. (Código é valido por 15min)\n\n${completarCadastroUrl}`;

// 🔹 Finalização
mensagem += `\n\nQualquer coisa, só me chamar por aqui.`;

// 🔹 Retorno
return [
  {
    json: {
      number: numero,
      text: mensagem
    }
  }
];

